input.command:
# 显示目录层级树结构（最多3层）
$root = "D:\CursorProject\Dadian - 副本\Arts\Assets\ArtResources\UIs\Prefabs"
Get-ChildItem -Path $root -Directory | ForEach-Object {
    $level1 = $_
    Write-Output "[DIR] $($level1.Name)"
    Get-ChildItem -Path $level1.FullName -Directory | ForEach-Object {
        $level2 = $_
        $count = (Get-ChildItem -Path $level2.FullName -Filter "*.prefab" -Recurse).Count
        Write-Output "  [DIR] $($level2.Name)  ($count prefabs)"
        Get-ChildItem -Path $level2.FullName -Directory | ForEach-Object {
            $level3 = $_
            $count3 = (Get-ChildItem -Path $level3.FullName -Filter "*.prefab" -Recurse).Count
            Write-Output "    [DIR] $($level3.Name)  ($count3 prefabs)"
        }
    }
    $rootCount = (Get-ChildItem -Path $level1.FullName -Filter "*.prefab").Count
    if ($rootCount -gt 0) { Write-Output "  (直接含 $rootCount 个 prefab)" }
}
# 根目录直接包含的 prefab 数
$directRoot = (Get-ChildItem -Path $root -Filter "*.prefab").Count
Write-Output "`n根目录直接含 prefab: $directRoot"

