# 统计3个样本文件的行数
$files = @(
  "D:\CursorProject\Dadian - 副本\Arts\Assets\ArtResources\UIs\Prefabs\Main\UI_Main.prefab",
  "D:\CursorProject\Dadian - 副本\Arts\Assets\ArtResources\UIs\Prefabs\Guild\UI_GuildMain.prefab",
  "D:\CursorProject\Dadian - 副本\Arts\Assets\ArtResources\UIs\Prefabs\Common\UI_CommonPurchase.prefab"
)
foreach ($f in $files) {
    $lines = (Get-Content $f).Count
    Write-Output "$([System.IO.Path]::GetFileName($f)): $lines 行"
}

# 检查各文件夹中 prefab 数量统计（排除 ExpandRes 子目录）
$root = "D:\CursorProject\Dadian - 副本\Arts\Assets\ArtResources\UIs\Prefabs"
$dirs = Get-ChildItem -Path $root -Directory
$summary = @()
foreach ($d in $dirs) {
    $count = (Get-ChildItem -Path $d.FullName -Filter "*.prefab" -Recurse | Where-Object { $_.FullName -notlike "*ExpandRes*" }).Count
    $summary += [PSCustomObject]@{ Name=$d.Name; Count=$count }
}
$summary | Sort-Object Count -Descending | Format-Table -AutoSize

